// =============================================================================
// Planviry - Static Autocomplete Data (Pills + Travel + Tickets)
// =============================================================================
// Hand-curated autocomplete index sourced from the user-supplied spec.
//
// Exports:
//   - SPACES_PILLS: string[] (activity-type pills for the Spaces search)
//   - TRAVEL_AUTOCOMPLETE: AutocompleteItem[] (10 categories, ~1000 items)
//   - TICKETS_AUTOCOMPLETE: AutocompleteItem[] (19 categories, ~950 items)
//   - searchAllAutocomplete / searchTravelAutocomplete / searchTicketsAutocomplete
//
// Each AutocompleteItem has: { label, slug, href, category, group }
// =============================================================================

export interface AutocompleteItem {
  /** Human-readable label shown in the dropdown */
  label: string
  /** kebab-case identifier */
  slug: string
  /** Clickable URL — leads to a search results page scoped to this term */
  href: string
  /** Category the item belongs to (e.g. "Hotels by Location", "CONCERTS") */
  category: string
  /** Top-level group: "travel" | "tickets" */
  group: 'travel' | 'tickets'
}

