// ── Search helpers ───────────────────────────────────────────────────────────

/**
 * Case-insensitive substring search across both label and slug.
 * Returns up to `limit` matches, sorted by:
 *   1. label starts-with query (prefix match)
 *   2. slug starts-with query
 *   3. label contains query
 *   4. slug contains query
 */
function searchItems(
  items: AutocompleteItem[],
  query: string,
  limit = 10
): AutocompleteItem[] {
  const q = query.trim().toLowerCase()
  if (q.length === 0) return items.slice(0, limit)

  const prefix: AutocompleteItem[] = []
  const slugPrefix: AutocompleteItem[] = []
  const contains: AutocompleteItem[] = []
  const slugContains: AutocompleteItem[] = []

  for (const item of items) {
    const label = item.label.toLowerCase()
    const slug = item.slug.toLowerCase()
    if (label.startsWith(q)) {
      prefix.push(item)
    } else if (slug.startsWith(q)) {
      slugPrefix.push(item)
    } else if (label.includes(q)) {
      contains.push(item)
    } else if (slug.includes(q)) {
      slugContains.push(item)
    }
    if (
      prefix.length + slugPrefix.length + contains.length + slugContains.length >=
      limit * 4
    ) {
      break
    }
  }

  return [...prefix, ...slugPrefix, ...contains, ...slugContains].slice(0, limit)
}

/** Search across all autocomplete items (travel + tickets). */
export function searchAllAutocomplete(query: string, limit = 10): AutocompleteItem[] {
  const q = query.trim().toLowerCase()
  if (q.length === 0) return []
  return searchItems(
    [...TRAVEL_AUTOCOMPLETE, ...TICKETS_AUTOCOMPLETE],
    q,
    limit
  )
}

/** Search only travel autocomplete items. */
export function searchTravelAutocomplete(query: string, limit = 10): AutocompleteItem[] {
  const q = query.trim().toLowerCase()
  if (q.length === 0) return []
  return searchItems(TRAVEL_AUTOCOMPLETE, q, limit)
}

/** Search only tickets autocomplete items. */
export function searchTicketsAutocomplete(query: string, limit = 10): AutocompleteItem[] {
  const q = query.trim().toLowerCase()
  if (q.length === 0) return []
  return searchItems(TICKETS_AUTOCOMPLETE, q, limit)
}
